// ============================================================
// BUILD PROMPT — Pixformance Lead Scanner (DACH, janelas largas)
// ============================================================

const today = new Date().toISOString().split('T')[0];

// --- Dedup: leads já existentes na planilha ---
let existingLeads = "keine";
try {
  const rows = $('Dedup - Get row(s) in sheet').all();
  const nomes = rows
    .map(r => `${r.json.facility_name} (${r.json.city})`)
    .filter(n => n && n.trim() !== "()" && n.trim() !== " ()");
  if (nomes.length > 0) existingLeads = nomes.join(", ");
} catch (e) {
  existingLeads = "keine";
}

const prompt = `# ROLE
You are a B2B sales-signal research agent for Pixformance Sports GmbH (digital movement therapy station for physiotherapy practices, rehab centers and hybrid physio-fitness facilities in the DACH region). Your job: find named, real facilities showing buying signals and output them as structured leads.
Today's date: ${today}

# IDEAL CUSTOMER PROFILE (only these qualify)
- Owner-led physiotherapy practice or ambulant rehab center, DACH, ~5-25 employees
- >=150m2 usable space or a dedicated Trainingsflaeche/Geraeteraum
- Offers or plans Selbstzahler services: T-RENA, Rehasport, Praeventionskurse, KGG, medical training therapy, or "Therapie + Training unter einem Dach" hybrid concepts
- Secondary: Reha-Kliniken (ambulant), senior/active-aging facilities, BGM providers
- ANTI-ICP (exclude): solo practices <100m2, pure Hausbesuchspraxen, consumer gyms without therapy, hospitals without ambulant rehab

# BUYING SIGNALS TO HUNT (with lookback windows)
1. EXPANSION/OPENING (90 days): Praxiseroeffnung, Umzug in groessere Raeume, Erweiterung, Neubau Trainingsflaeche, integration into a fitness center
2. OWNERSHIP TRANSITION (120 days): Praxisuebernahme completed, Inhaberwechsel, new GmbH founding
3. CHRONIC CAPACITY PAIN (180 days): press/reviews documenting patient wait times of 4+ weeks, "Praxis am Limit", understaffing
4. ACTIVE HIRING / JOB POSTINGS (120 days): the facility is actively advertising for physiotherapists. This is one of the STRONGEST signals of a capacity bottleneck. Search job boards and check the posting date:
   - Sources: physio.de/stellenmarkt, therapie.de, medi-jobs.de, Indeed.de, StepStone.de, kimeta.de, and the facility's own "Karriere"/"Jobs" page
   - Strong sub-signal: a posting open or reposted 60+ days (they can't fill it -> they have demand they can't serve)
   - Stronger still: a facility advertising MULTIPLE open physio roles at once, or hiring for a NEW Trainingsflaeche/Standort
   - Record the posting date in signal_date and note the role(s) in signal_summary
5. PROFESSIONAL RECRUITING / HEADHUNTING (120 days): the facility is investing in acquiring staff beyond a simple ad — e.g. working with a Personalvermittlung/recruiter, offering signing bonuses (Willkommensbonus/Wechselpraemie), aggressive benefits, or "Wir wachsen – Team gesucht" campaigns. Signals active growth and budget. Check LinkedIn, Indeed, XING, facility career pages and local press.
6. COMPETITIVE PRESSURE (90 days): nearby facility announcing competitor device installs (Sensopro, YOLii, Pelvi, Just Functional, EGYM, milon, five)
7. FUNDING WINDOW (90 days): new Laender-level Digitalisierungs-/BGM-/Praeventions-Foerderprogramme relevant to therapy facilities

# SEARCH STRATEGY
You MUST cover all three DACH countries in every scan — not only Germany. Distribute your searches so that Germany, Austria, and Switzerland each receive dedicated queries. With 3 searches available, allocate at minimum: 1 search targeting Austria (AT) and 1 search targeting Switzerland (CH); the remainder may target Germany (DE). Do NOT spend all searches on German regions.

For AUSTRIA (AT): use Austrian-specific terms and sources — e.g. "Physiotherapie Praxis Eröffnung Österreich", "Physiotherapeut gesucht Wien Graz Linz Salzburg Innsbruck", and sources like meinbezirk.at, karriere.at, willhaben.at, and Austrian regional press. Search across Austrian Bundesländer (Wien, Niederösterreich, Oberösterreich, Steiermark, Tirol, Salzburg, Kärnten, Vorarlberg).

For SWITZERLAND (CH): use Swiss-specific terms and sources — e.g. "Physiotherapie Praxis Eröffnung Schweiz", "Physiotherapeut gesucht Zürich Bern Basel", and sources like jobs.ch, physioswiss.ch, and Swiss regional press. Search across Swiss cantons (Zürich, Bern, Basel, Aargau, St. Gallen, Luzern, Waadt/Vaud, Genf/Genève).

For GERMANY (DE): rotate across Bundesländer each scan (NRW, Bayern, Baden-Württemberg, Niedersachsen, Hessen, Sachsen, Berlin) and use German sources: physio.de/stellenmarkt, therapie.de, medi-jobs.de, Indeed.de, StepStone.de, neueroeffnung.info, openpr.de, BODYMEDIA, up-aktuell.

When you find a job posting, open it and check the publication date to estimate how long the role has been open. Prioritize local press and real job postings over national think-pieces. A usable lead MUST have a facility name and location. Trend articles without named facilities are NOT leads. Set the "country" field correctly to DE, AT, or CH based on the facility's actual location.

# SCORING (0-100)
score = signal_strength (0-40: opening/takeover/expansion=35-40, active hiring/job posting 60+ days=35, capacity pain=25-35, headhunting/recruiting=25-30, competitor/funding=15-25) + ICP_fit (0-40: training floor mentioned=+15, hybrid concept=+15, team size 5-25=+10) + freshness (0-20: <30 days=20, <90=12, <180=5). Discard below 50.

# VERIFICATION RULES
- Every lead needs at least one working source URL
- Never invent any data. Unknown = "TBD"
- Flag signals older than 90 days in signal_summary with "VERIFY CURRENT STATUS"
- Exclude facilities that already announced buying a Pixformance Station

# DEDUPLICATION (CRITICAL)
The following practices were already reported in previous scans.
Do NOT output any of them again — not even with slightly different name or spelling.
If you encounter one of these, skip it and keep searching for NEW leads:
${existingLeads}

# OUTPUT - respond with ONLY a JSON array, no markdown fences, no preamble:
[{"facility_name":"","city":"","country":"DE|AT|CH","address":"","contact_person":"","role":"","phone":"","website":"","signal_type":"expansion|takeover|opening|capacity_pain|staffing|hiring|headhunting|competitor|funding","signal_summary":"1-2 sentences, German","signal_date":"YYYY-MM-DD","score":0,"talking_angle":"1 sentence, German","source_urls":[""]}]
If you find NO qualifying new leads, respond with an empty array: []
Do NOT write explanations or any text outside the JSON array.
Return the top 3 leads ranked by score descending if found... never invent or fabricate any result. Always return valid JSON.`;

return [{
  json: {
    model: "claude-sonnet-4-6",
    max_tokens: 5000,
    messages: [{ role: "user", content: prompt }],
    tools: [{ type: "web_search_20250305", name: "web_search", max_uses: 3 }]
  }
}];

// ============================================================
// CODE PARSE — Pixformance Lead Scanner
// Extrai o array de leads da resposta do Anthropic.
// Robusto contra: cercas markdown (```json), array indentado
// ([ \n  { ), preâmbulo antes do array, e resposta vinda
// como array / body / objeto direto.
// ============================================================

// 1) Normaliza a resposta (pode vir como [0], como body, ou objeto direto)
const raw = $input.first().json;
const response = Array.isArray(raw) ? raw[0] : (raw.body ?? raw);

// 2) Junta todo o texto dos blocos "text" da resposta
const text = (response.content || [])
  .filter(b => b.type === "text")
  .map(b => b.text)
  .join("\n");

// 3) Remove cercas markdown (```json ... ``` ou ``` ... ```)
let limpo = text.replace(/```json/gi, "").replace(/```/g, "");

// 4) Acha o array JSON de leads, tolerando espaços/quebras entre [ e {
//    Procura o primeiro "[" que, ignorando espaços/quebras, é seguido de "{"
function acharInicioArray(s) {
  for (let i = 0; i < s.length; i++) {
    if (s[i] !== "[") continue;
    let j = i + 1;
    while (j < s.length && /\s/.test(s[j])) j++; // pula espaços/quebras
    if (s[j] === "{") return i; // é um array de objetos
  }
  return -1;
}

// 5) A partir do "[", varre com contador de profundidade respeitando strings
function extrairArray(s) {
  const inicio = acharInicioArray(s);
  if (inicio === -1) return null;
  let prof = 0, str = false, esc = false;
  for (let i = inicio; i < s.length; i++) {
    const c = s[i];
    if (esc) { esc = false; continue; }
    if (c === "\\") { esc = true; continue; }
    if (c === '"') { str = !str; continue; }
    if (str) continue;
    if (c === "[") prof++;
    else if (c === "]") { prof--; if (prof === 0) return s.slice(inicio, i + 1); }
  }
  return null;
}

const jsonStr = extrairArray(limpo);
if (!jsonStr) return [];

let leads;
try {
  leads = JSON.parse(jsonStr);
} catch (e) {
  return [];
}
if (!Array.isArray(leads) || leads.length === 0) return [];

// 6) Monta os items de saída (um por lead)
const scanDate = new Date().toISOString().slice(0, 10);

return leads.map(lead => {
  const leadKey = ((lead.facility_name ?? "") + "_" + (lead.city ?? ""))
    .toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")   // tira acentos
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "");

  return {
    json: {
      scan_datum: scanDate,
      lead_key: leadKey,
      facility_name: lead.facility_name ?? "",
      city: lead.city ?? "",
      country: lead.country ?? "",
      address: lead.address ?? "",
      contact_person: lead.contact_person ?? "",
      role: lead.role ?? "",
      phone: lead.phone ?? "",
      website: lead.website ?? "",
      signal_type: lead.signal_type ?? "",
      signal_summary: lead.signal_summary ?? "",
      signal_date: lead.signal_date ?? "",
      score: lead.score ?? "",
      talking_angle: lead.talking_angle ?? "",
      source_urls: Array.isArray(lead.source_urls)
        ? lead.source_urls.join(" | ")
        : (lead.source_urls ?? ""),
      status: ""
    }
  };
});

// Code Merge — Mode: Run Once for Each Item
const itemIndex = $itemIndex;

// lead original vem do "Code Parse" (nome exato do seu nó de parse)
const lead = { ...$('Code Parse').all()[itemIndex].json };

// candidatos do Places (até 3)
const candidatos = $json.places || [];

const norm = s => (s || "")
  .toLowerCase()
  .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
  .replace(/[^a-z0-9 ]/g, " ")
  .replace(/\s+/g, " ")
  .trim();

const cidadeLead   = norm(lead.city);
const palavrasLead = norm(lead.facility_name).split(" ").filter(w => w.length > 3);

function pontuar(place) {
  const endereco = norm(place?.formattedAddress);
  const nome     = norm(place?.displayName?.text);
  let p = 0;
  if (cidadeLead && endereco.includes(cidadeLead)) p += 2;
  for (const w of palavrasLead) if (nome.includes(w)) p += 1;
  return p;
}

let melhor = null, melhorScore = 0;
for (const c of candidatos) {
  const s = pontuar(c);
  if (s > melhorScore) { melhorScore = s; melhor = c; }
}

// aceita só se cidade bateu E pelo menos uma palavra do nome (score >= 3)
const matchOk = melhor && melhorScore >= 3;

if (matchOk) {
  lead.phone   = melhor.nationalPhoneNumber || lead.phone;
  lead.website = melhor.websiteUri          || lead.website;
  lead.address = melhor.formattedAddress    || lead.address;
  lead.places_match = "ok";
  lead.places_name  = melhor.displayName?.text || "";
} else {
  lead.places_match = "no_match";
  lead.places_name  = melhor?.displayName?.text || (candidatos[0]?.displayName?.text || "");
}

if (lead.phone === "TBD")   lead.phone = "";
if (lead.website === "TBD") lead.website = "";

return { json: lead };
